    odd = sum(1 for i in num if int(i) % 2!= 0)
    even = sum(1 for i in num if int(i) % 2 == 0)
    return odd, even

def int_to_mini_roman(number):
    """
    Given a positive integer, obtain its roman numeral equivalent as a string,
    and return it in lowercase.
    Restrictions: 1 <= num <= 1000

    Examples:
    >>> int_to_mini_roman(19) == 'xix'
    >>> int_to_mini_roman(152) == 'clii'
    >>> int_to_mini_roman(426) == 'cdxxvi'
    """
    result = ''
    value_to_numeral_dict = {
        1: "i", 4: "iv", 5: "v", 9: "ix", 10: "x", 40: "xl", 50: "l", 90: "xc", 100: "c", 400: "cd", 500: "d", 900: "cm", 1000: "m"
    }
    value_to_numeral_dict_reverse = {
        1: "i", 4: "iv", 5: "v", 9: "ix", 10: "x", 40: "xl", 50: "l", 90: "xc", 100: "c", 400: "cd", 500: "d", 900: "cm", 1000: "m"
    }
    value_to_numeral_dict_reverse_order = {}
    for key, value in value_to_numeral_dict.items():
        value_to_numeral_dict_reverse_order[value] = key
    value_to_numeral_dict_reverse_order_keys = list(value_to_numeral_dict_reverse_order.keys())

    while number > 0:
        for key in value_to_numeral_dict_reverse_order_keys:
            if number >= value_to_numeral_dict_reverse_order[key]:
                result += key
                number -= value_to_numeral_dict_reverse_order[key]
                break
    return result

